/** Make `Vector 9 (Stroke)` — decorative rounded-rect outline behind the mark. */
const HOME_LOGO_OUTLINE_D =
  "M218.562 0V54H0V45.7039H1.40204V52.5954H217.16V1.40463H1.40204V8.69114H0V0H218.562Z";

function HomeLogo() {
  return (
    <div className="home__logo" data-name="boots.ai assistant 3" aria-hidden>
      <span className="home__logo-outline">
        <svg viewBox="0 0 218.562 54" fill="none">
          <path d={HOME_LOGO_OUTLINE_D} fill="#261F4B" />
        </svg>
      </span>
      <span className="home__logo-mark">
        <svg viewBox="0 0 67.9523 34.5477" fill="none">
          <path
            fillRule="evenodd"
            clipRule="evenodd"
            d={HOME_LOGO_MARK_D}
            fill="#241E5B"
          />
        </svg>
      </span>
      <span className="home__logo-wordmark">
        <svg viewBox="0 0 142.979 12.7273" fill="none">
          {SITE_PILOT_WORDMARK_D.map((d, i) => (
            <path key={i} d={d} fill="#29254C" />
          ))}
        </svg>
      </span>
    </div>
  );
}

export function HomeScreen({
  loggedIn,
  initialQuery,
  onSend,
  onChip,
  onQueryDirtyChange,
}: HomeScreenProps) {
  const [query, setQuery] = useState(
    () => initialQuery ?? HOME_QUERY_DEFAULT
  );

  const chips = useMemo(
    () =>
      HOME_CHIP_LABELS.map((label) => ({
        label,
        slug: homeChipSlug(label),
        actionId: homeChipActionId(label),
      })),
    []
  );

  useEffect(() => {
    const dirty = query.trim() !== HOME_QUERY_DEFAULT.trim();
    onQueryDirtyChange?.(dirty);
  }, [query, onQueryDirtyChange]);

  return (
    <main
      className="home"
      data-studio-react-screen={HOME_REACT_SCREEN_ID}
      data-name="body"
      aria-label="Agentic Site Pilot home"
    >
      <div className="home__content">
        <HomeLogo />

        <h1
          className="home__heading"
          data-studio-agentic-home-heading="true"
        >
          {resolveHomeHeading(loggedIn)}
        </h1>

        <section
          className="home__card"
          data-name="component.co.order.summary"
          aria-label="Ask Site Pilot"
        >
          <SitePilotComposer
            surface="home"
            query={query}
            onQueryChange={setQuery}
            onSend={() => onSend(query)}
            showSuggested
            suggestedLabel={HOME_SUGGESTED_LABEL}
            suggestedLabelId={HOME_SUGGESTED_LABEL_ID}
            chips={chips}
            onChip={(label) => onChip(label as HomeChipLabel)}
          />
        </section>
      </div>
    </main>
  );
}
